"use strict";(()=>{window.Webflow||(window.Webflow=[]);window.Webflow.push(()=>{let n=document.querySelector('[data="dd-block"]'),c=document.querySelector('[data="dd-header"]'),i=document.querySelector('[data="dd-table"]');n?.addEventListener("click",()=>{let e=c?.classList.contains("active");c?.classList.toggle("active",!e),i?.classList.toggle("active",!e)});let o=document.querySelectorAll(".content-block-anchor"),t=document.querySelectorAll(".toc-item");if(!o.length||!t.length)return;let a=()=>{t.forEach(e=>e.classList.remove("is-active"))};t[0].classList.add("is-active");let d=new IntersectionObserver(e=>{e.forEach(s=>{if(!s.isIntersecting)return;a();let l=s.target.id;t.forEach(r=>{r.querySelector("a.toc-link")?.getAttribute("href")==="#"+l&&r.classList.add("is-active")})})},{rootMargin:"-100px 0px -65% 0px",threshold:0});o.forEach(e=>d.observe(e))});})();
